{
  "public_summary": "唐纳德·特朗普在百周年纪念讲堂内稳立发言位，面向全场，以标志性简洁风格回应学生关切。",
  "environment_instruction": "保持站立姿态，目光平视前方人群，微微颔首示意，展现专注而开放的交流状态。",
  "action_proposal": {
    "action_type": "group_message",
    "content": "好问题。政策应锁定真实滥用风险，而不是挡住普通学生和研究者。开放研究、可复现实验、青年交流，应留下清晰通道。",
    "public": true
  }
}

{
  "public_summary": "唐纳德·特朗普面向陈同学方向微微颔首，目光沉稳，以简洁有力的风格回应芯片方向学生的提问。",
  "environment_instruction": "面向提问者陈同学方向自然点头示意，保持站立姿态与开放眼神交流，展现专注倾听后的直接回应状态。",
  "action_proposal": {
    "action_type": "direct_message",
    "receiver_id": 15,
    "content": "政策不该设路障，而应修桥梁。学生和研究者需要的是可预测、可申请、可复现的通道——不是许可，而是支持。"
  }
}

{
  "public_summary": "唐纳德·特朗普转向沈同学方向，目光坚定而简洁，以标志性直率风格回应关于AI权力集中与青年参与的问题。",
  "environment_instruction": "面向提问者沈同学自然转头示意，微微颔首，保持站立姿态与开放眼神交流，展现专注回应状态。",
